class Solution(object):
    def maximumGap(self, nums):
        n = len(nums)
        if n < 2:
            return 0
        # Radix sort for O(n) linear time
        def radix_sort(arr):
            max_val = max(arr)
            exp = 1
            while max_val // exp > 0:
                count = [0] * 10
                for x in arr:
                    count[(x // exp) % 10] += 1
                for i in range(1, 10):
                    count[i] += count[i-1]
                output = [0] * len(arr)
                for i in range(len(arr)-1, -1, -1):
                    digit = (arr[i] // exp) % 10
                    count[digit] -= 1
                    output[count[digit]] = arr[i]
                arr = output
                exp *= 10
            return arr

        nums = radix_sort(nums)
        ans = 0
        for i in range(1, n):
            ans = max(ans, nums[i] - nums[i-1])
        return ans
